import{_ as e,o as s,c as n,ag as t}from"./chunks/framework.BDReElpY.js";const h=JSON.parse('{"title":"Mutability and Borrowing Rules","description":"","frontmatter":{},"headers":[],"relativePath":"archive/reference/mutability.md","filePath":"archive/reference/mutability.md"}'),i={name:"archive/reference/mutability.md"};function l(p,a,r,o,c,u){return s(),n("div",null,[...a[0]||(a[0]=[t(`<h1 id="mutability-and-borrowing-rules" tabindex="-1">Mutability and Borrowing Rules <a class="header-anchor" href="#mutability-and-borrowing-rules" aria-label="Permalink to &quot;Mutability and Borrowing Rules&quot;">​</a></h1><p><strong>Core Language Specification</strong><br><strong>Version:</strong> 0.2.0<br><strong>Status:</strong> ✅ Implemented</p><p>This document details the exact rules enforced by the Vex Borrow Checker (Phases 1-4).</p><hr><h2 id="_1-variable-mutability-let-vs-let" tabindex="-1">1. Variable Mutability (<code>let</code> vs <code>let!</code>) <a class="header-anchor" href="#_1-variable-mutability-let-vs-let" aria-label="Permalink to &quot;1. Variable Mutability (\`let\` vs \`let!\`)&quot;">​</a></h2><p>Mutability is opt-in.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let x = 10;</span></span>
<span class="line"><span>// x = 20;</span><span> // Error: Immutable assignment</span></span>
<span class="line"><span></span></span>
<span class="line"><span>let! y = 10;</span></span>
<span class="line"><span>y = 20; // OK</span></span></code></pre></div><ul><li><strong>Deep Mutability</strong>: <code>let! x = Struct { ... }</code> makes the <em>entire</em> struct mutable. Vex does not support partial field mutability (except via interior mutability types like <code>Cell</code> - Future).</li></ul><hr><h2 id="_2-reference-mutability" tabindex="-1">2. Reference Mutability <a class="header-anchor" href="#_2-reference-mutability" aria-label="Permalink to &quot;2. Reference Mutability&quot;">​</a></h2><p>References inherit the mutability of their binding <em>at creation</em>, but enforce it strictly.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let! data = Vec.new();</span></span>
<span class="line"><span></span></span>
<span class="line"><span>fn process(v: &amp;Vec&lt;i32&gt;!) {</span></span>
<span class="line"><span>    v.(1);</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>process(&amp;data); // Pass mutable reference</span></span></code></pre></div><h3 id="the-rules" tabindex="-1">The Rules <a class="header-anchor" href="#the-rules" aria-label="Permalink to &quot;The Rules&quot;">​</a></h3><ol><li><strong>No Alias + Mutation</strong>: You cannot have a mutable reference (<code>&amp;T!</code>) if <em>any</em> other reference (mutable or immutable) to the same data is active.</li><li><strong>Shared Read</strong>: You can have infinite immutable references (<code>&amp;T</code>).</li></ol><hr><h2 id="_3-interior-mutability-using-unsafe" tabindex="-1">3. Interior Mutability using <code>Unsafe</code> <a class="header-anchor" href="#_3-interior-mutability-using-unsafe" aria-label="Permalink to &quot;3. Interior Mutability using \`Unsafe\`&quot;">​</a></h2><p>To bypass these rules (e.g. for implementing smart pointers), one must use <code>unsafe</code> and <code>UnsafeCell</code>-like patterns.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>struct Cell&lt;T&gt; {</span></span>
<span class="line"><span>    value: T,</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>impl Cell&lt;T&gt; {</span></span>
<span class="line"><span>    fn set(self: &amp;Cell&lt;T&gt;, val: T) {</span></span>
<span class="line"><span>        unsafe {</span></span>
<span class="line"><span>             // Cast immutable self to mutable pointer</span></span>
<span class="line"><span>             let ptr = self as *Cell&lt;T&gt;!;</span></span>
<span class="line"><span>             (*ptr).value = val;</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span></code></pre></div><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p>Bypassing the borrow checker is undefined behavior if data races occur. Only use this for single-threaded synchronization primitives or FFI.</p></div>`,19)])])}const b=e(i,[["render",l]]);export{h as __pageData,b as default};
